import axios from 'axios';

const API_BASE_URL = 'http://localhost:5001'; // Tr·ªè v·ªÅ server Admin

class ProductService {
    // L·∫•y danh s√°ch s·∫£n ph·∫©m
    async getAllProducts() {
        const token = localStorage.getItem("token");
        const res = await axios.get(`${API_BASE_URL}/api/products`, { // S·∫øp ch·ªânh l·∫°i endpoint cho kh·ªõp Backend
            headers: { Authorization: `Bearer ${token}` }
        });
        return res.data;
    }

    // L·∫•y danh s√°ch danh m·ª•c
    async getAllCategories() {
        const token = localStorage.getItem("token");
        const res = await axios.get(`${API_BASE_URL}/api/categories`, {
            headers: { Authorization: `Bearer ${token}` }
        });
        return res.data;
    }

    // Th√™m/S·ª≠a s·∫£n ph·∫©m
    async saveProduct(productData, isEdit) {
        const token = localStorage.getItem("token");
        const url = isEdit 
            ? `${API_BASE_URL}/api/products/${productData.product_id}` 
            : `${API_BASE_URL}/api/products`;
        
        const method = isEdit ? "put" : "post";
        return await axios[method](url, productData, {
            headers: { Authorization: `Bearer ${token}` }
        });
    }

    // X√≥a s·∫£n ph·∫©m
    async deleteProduct(id) {
        const token = localStorage.getItem("token");
        return await axios.delete(`${API_BASE_URL}/api/products/${id}`, {
            headers: { Authorization: `Bearer ${token}` }
        });
    }
}

export default new ProductService();
